export function matchesQuery(fields, query) {
  if (!query.trim()) return true;
  const normalized = query.trim().toLowerCase();
  return fields.some(field => `${field ?? ''}`.toLowerCase().includes(normalized));
}
export function sortByDate(items, getDate, order) {
  return [...items].sort((a, b) => {
    const left = new Date(getDate(a) ?? '').getTime() || 0;
    const right = new Date(getDate(b) ?? '').getTime() || 0;
    return order === 'asc' ? left - right : right - left;
  });
}
export function paginate(items, page, pageSize) {
  const start = Math.max(0, (page - 1) * pageSize);
  return items.slice(start, start + pageSize);
}
export function totalPages(totalItems, pageSize) {
  return Math.max(1, Math.ceil(totalItems / pageSize));
}
